import numpy as np

def solve_quadratic(a, b, c):
    disc = b**2 - 4*a*c
    if disc > 0:
        x1 = (-b + disc**0.5) / (2*a)
        x2 = (-b - disc**0.5) / (2*a)
        return (x1, x2)
    elif disc == 0:
        return (-b / (2*a),)
    else:
        return ()  # אין פתרונות ממשיים

print(solve_quadratic(2, -4, -6))  # (3.0, -1.0)
print(solve_quadratic(1, -4, 4))   # (2.0,)
print(solve_quadratic(1, 1, 1))    # ()
